import{P as i}from"./chunks/PublicUtilityPanel.QYoIU9MT.js";import{o as e,c as r,ag as s,E as o}from"./chunks/framework.DmPmGTlv.js";import"./chunks/theme.BsBmJ8k5.js";const u=JSON.parse('{"title":"Legislação","description":"","frontmatter":{},"headers":[],"relativePath":"legislacao.md","filePath":"pt/legislacao.md","lastUpdated":1777069591000}'),t={name:"legislacao.md"},m=Object.assign(t,{setup(c){return(l,a)=>(e(),r("div",null,[a[0]||(a[0]=s('<h1 id="legislacao" tabindex="-1">Legislação <a class="header-anchor" href="#legislacao" aria-label="Permalink to &quot;Legislação&quot;">​</a></h1><blockquote><p>Conteúdo informativo. Esta página organiza referências públicas e oficiais. Ela não substitui orientação médica, jurídica ou regulatória individual.</p></blockquote><h2 id="marco-regulatorio-principal" tabindex="-1">Marco regulatório principal <a class="header-anchor" href="#marco-regulatorio-principal" aria-label="Permalink to &quot;Marco regulatório principal&quot;">​</a></h2><div class="docs-grid docs-grid-2"><article class="surface-card"><p class="docs-kicker">Planalto</p><h3>Lei 11.343/2006</h3><p> A Lei de Drogas continua sendo a base legal do tema no Brasil. O texto legal permite que a União autorize, sob fiscalização, o cultivo para fins medicinais ou científicos. </p><p><a href="https://www.planalto.gov.br/ccivil_03/_ato2004-2006/2006/lei/l11343.htm?authuser=0" target="_blank" rel="noreferrer"> Abrir lei no Planalto </a></p></article><article class="surface-card"><p class="docs-kicker">STJ · 13 nov 2024</p><h3>IAC 16 e o cânhamo industrial medicinal</h3><p> Em 13 de novembro de 2024, o STJ fixou teses para reconhecer a possibilidade jurídica de cultivo por pessoas jurídicas, para fins medicinais e farmacêuticos, com THC inferior a 0,3%, e determinou prazo para regulamentação. </p><p><a href="https://www.stj.jus.br/sites/portalp/Paginas/Comunicacao/Noticias/2024/14112024-STJ-valida-cultivo-medicinal-da-cannabis-por-empresas-e-da-prazo-para-regulamentacao.aspx" target="_blank" rel="noreferrer"> Ver notícia oficial do STJ </a></p></article><article class="surface-card"><p class="docs-kicker">STJ · 28 fev 2025</p><h3>Prazo regulatório mantido</h3><p> Em 28 de fevereiro de 2025, o STJ negou pedido de mais prazo da Anvisa e da União. Na prática, o tribunal reforçou a exigência de regulamentação dentro da contagem iniciada em 19 de novembro de 2024. </p><p><a href="https://www.stj.jus.br/sites/portalp/Paginas/Comunicacao/Noticias/2025/28022025-Negado-pedido-da-Anvisa-por-mais-prazo-para-regulamentar-uso-da-cannabis-com-fins-medicinais.aspx" target="_blank" rel="noreferrer"> Ver atualização do STJ </a></p></article><article class="surface-card"><p class="docs-kicker">Anvisa · jan/fev 2026</p><h3>RDCs 1.012 a 1.015/2026</h3><p> Em 2026, a Anvisa aprovou novas regras para pesquisa, produção por pessoas jurídicas, associações de pacientes e atualização do marco de fabricação e importação. A própria agência informou, naquele momento, 49 produtos regularizados e 59 empresas autorizadas a importar insumos. </p><p><a href="https://www.gov.br/anvisa/pt-br/assuntos/noticias-anvisa/2026/anvisa-aprova-por-unanimidade-regras-que-cumprem-decisao-do-stj-para-producao-de-cannabis-medicinal" target="_blank" rel="noreferrer"> Ver publicação oficial da Anvisa </a></p></article></div><h2 id="o-que-isso-significa-na-pratica" tabindex="-1">O que isso significa na prática <a class="header-anchor" href="#o-que-isso-significa-na-pratica" aria-label="Permalink to &quot;O que isso significa na prática&quot;">​</a></h2><div class="surface-card"><ul class="stack-list"><li><strong>Importação excepcional:</strong> continua sendo uma rota oficial para pessoa física com prescrição e cadastro na Anvisa. </li><li><strong>Farmácias e drogarias:</strong> o acesso a produtos regularizados segue vinculado ao marco sanitário da Anvisa e às exigências de receita e controle aplicáveis. </li><li><strong>Associações de pacientes:</strong> passaram a ter instrumento regulatório específico em 2026, mas isso não elimina requisitos administrativos, clínicos, documentais e jurídicos. </li><li><strong>Portal ABPCM:</strong> organiza essas referências em linguagem prática para pacientes, famílias, prescritores e apoiadores. </li></ul></div><h2 id="links-oficiais-prioritarios" tabindex="-1">Links oficiais prioritários <a class="header-anchor" href="#links-oficiais-prioritarios" aria-label="Permalink to &quot;Links oficiais prioritários&quot;">​</a></h2><div class="docs-grid docs-grid-2"><article class="surface-card"><p class="docs-kicker">Anvisa</p><h3>Acesso e controle sanitário</h3><div class="link-cluster"><a href="https://www.gov.br/anvisa/pt-br/assuntos/medicamentos/controlados/cannabis" class="link-pill" target="_blank" rel="noreferrer"> Importação e cannabis </a><a href="https://www.gov.br/anvisa/pt-br/assuntos/noticias-anvisa/2026/anvisa-aprova-por-unanimidade-regras-que-cumprem-decisao-do-stj-para-producao-de-cannabis-medicinal" class="link-pill" target="_blank" rel="noreferrer"> Regras de 2026 </a></div></article><article class="surface-card"><p class="docs-kicker">Judiciário e lei</p><h3>Base normativa e jurisprudencial</h3><div class="link-cluster"><a href="https://www.stj.jus.br/sites/portalp/Paginas/Comunicacao/Noticias/2024/14112024-STJ-valida-cultivo-medicinal-da-cannabis-por-empresas-e-da-prazo-para-regulamentacao.aspx" class="link-pill" target="_blank" rel="noreferrer"> STJ 2024 </a><a href="https://www.stj.jus.br/sites/portalp/Paginas/Comunicacao/Noticias/2025/28022025-Negado-pedido-da-Anvisa-por-mais-prazo-para-regulamentar-uso-da-cannabis-com-fins-medicinais.aspx" class="link-pill" target="_blank" rel="noreferrer"> STJ 2025 </a><a href="https://www.planalto.gov.br/ccivil_03/_ato2004-2006/2006/lei/l11343.htm?authuser=0" class="link-pill" target="_blank" rel="noreferrer"> Lei 11.343/2006 </a></div></article></div><h2 id="como-usar-esta-pagina" tabindex="-1">Como usar esta página <a class="header-anchor" href="#como-usar-esta-pagina" aria-label="Permalink to &quot;Como usar esta página&quot;">​</a></h2><ol><li>Leia primeiro a base legal e sanitária para entender qual rota faz sentido para o seu caso.</li><li>Cruze a informação com a página de <a href="/node-vitepress-abpcm/acesso">Acesso</a> e com a documentação clínica do paciente.</li><li>Em caso de dúvida concreta sobre tratamento, cultivo, dispensação ou judicialização, avance apenas com orientação profissional individualizada.</li></ol><h2 id="utilidades-publicas" tabindex="-1">Utilidades públicas <a class="header-anchor" href="#utilidades-publicas" aria-label="Permalink to &quot;Utilidades públicas&quot;">​</a></h2>',11)),o(i)]))}});export{u as __pageData,m as default};
